export type Cell = [number, number];

const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
  (x1 !== x2 || y1 !== y2) &&
  Math.abs(x1 - x2) <= 1 &&
  Math.abs(y1 - y2) <= 1;

const countNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => isNeighbor(cell, other)).length;

const isAlive = (cell: Cell, cells: Cell[]): boolean =>
  cells.some(([x, y]) => x === cell[0] && y === cell[1]);

const candidateCells = (cells: Cell[]): Cell[] => {
  const seen = new Set<string>();
  const result: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const key = `${x + dx},${y + dy}`;
        if (!seen.has(key)) {
          seen.add(key);
          result.push([x + dx, y + dy]);
        }
      }
    }
  }
  return result;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  return candidateCells(cells).filter((cell) => {
    const neighbors = countNeighbors(cell, cells);
    if (isAlive(cell, cells)) {
      return neighbors === 2 || neighbors === 3;
    }
    return neighbors === 3;
  });
}
